(function($){$(window).on("elementor/frontend/init",function(){var WPMOZOAdvancedTooltip=elementorModules.frontend.handlers.Base.extend({bindEvents:function(){this.change()},change:function(){const $tooltips=this.$element.find('.wpmozo_advanced_tooltip');if(!$tooltips.length)return;$tooltips.each(function(){let $this=$(this),$wrap=$this.find('.wpmozo_tooltip_trigger_element_wrap');let triggerType=$wrap.data('trigger-action')||'mouseenter',animationType=$wrap.data('animation')||'fade',duration=parseInt($wrap.data('duration'))||350,interactive=$wrap.data('interactive')===!0||$wrap.data('interactive')==='true',width=$wrap.data('tooltip-width')||'350',triggerEl=$wrap.data('trigger-element')||'button',triggerSelector=$wrap.data('trigger-selector')||'';let $tooltipContent=$this.find('.wpmozo_advanced_tooltip_content_wrap');if(!$tooltipContent.length)return;let $triggerElement=$this.find('.wpmozo_tooltip_trigger_element');if(triggerEl==='id'){$triggerElement=$('#'+triggerSelector)}else if(triggerEl==='class'){$triggerElement=$('.'+triggerSelector)}
tippy($triggerElement[0],{content:$tooltipContent.html(),placement:'auto',trigger:triggerType,animation:animationType,duration:duration,theme:'light',delay:[100,100],arrow:!1,allowHTML:!0,interactive:interactive,appendTo:()=>document.body,maxWidth:width,popperOptions:{modifiers:[{name:'flip',options:{fallbackPlacements:['top','bottom','left','right']}},{name:'zIndex',enabled:!0,phase:'write',fn({state}){state.elements.popper.style.zIndex='99999'}}]}});if(triggerType==='click'&&$this.find('.wpmozo_tooltip_trigger_button').length>0){$this.on('click','.wpmozo_tooltip_trigger_button',function(e){e.preventDefault()})}})},});elementorFrontend.elementsHandler.attachHandler("wpmozo_ae_advanced_tooltip",WPMOZOAdvancedTooltip)})})(jQuery)